  if (typeof import.meta !== 'undefined' && (import.meta as Record<string, unknown>).env != null) {
    return (import.meta as { env: { DEV?: boolean } }).env.DEV === true
  }
  return typeof process !== 'undefined' && process.env?.NODE_ENV !== 'production'
}

